import{_ as s,o as a,c as n,ah as t}from"./chunks/framework.ojwJKwrc.js";const h=JSON.parse('{"title":"Veryl analyzer and simulator upstream issues","description":"","frontmatter":{},"headers":[],"relativePath":"internals/veryl-analyzer-upstream-issues.md","filePath":"internals/veryl-analyzer-upstream-issues.md"}'),o={name:"internals/veryl-analyzer-upstream-issues.md"};function i(r,e,l,c,d,p){return a(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="veryl-analyzer-and-simulator-upstream-issues" tabindex="-1">Veryl analyzer and simulator upstream issues <a class="header-anchor" href="#veryl-analyzer-and-simulator-upstream-issues" aria-label="Permalink to &quot;Veryl analyzer and simulator upstream issues&quot;">​</a></h1><p>This is a worklist for fixes to send upstream to Veryl. It is not a list of Celox compatibility rules. Each issue must first be reproduced with the unmodified analyzer and simulator, then compared with the SystemVerilog emitted from the same source.</p><p>Verified revisions:</p><ul><li><a href="https://github.com/veryl-lang/veryl/releases/tag/v0.20.2" target="_blank" rel="noreferrer">latest release <code>v0.20.2</code></a> (<code>db27d32e812141dbe6530b8c4cd5875a3f03dc5b</code>)</li><li><a href="https://github.com/veryl-lang/veryl/commit/0230fbe76b8b4fd67bc09b2aa0378a6e96e0683f" target="_blank" rel="noreferrer">upstream <code>master</code></a> (<code>0230fbe76b8b4fd67bc09b2aa0378a6e96e0683f</code>)</li></ul><p>The four issue groups below are present in 0.20.2 and remain in that <code>master</code> revision. The 99 commits after 0.20.2 contain no fix that supersedes them.</p><h2 id="air-facts-that-are-not-analyzer-bugs" tabindex="-1">AIR facts that are not analyzer bugs <a class="header-anchor" href="#air-facts-that-are-not-analyzer-bugs" aria-label="Permalink to &quot;AIR facts that are not analyzer bugs&quot;">​</a></h2><p>AIR does not encode signedness solely in an expression&#39;s result type. It also keeps the operand evaluation context and represents a variable selection as a base variable plus <code>VarSelect</code>. Consumers must apply the operator/select rules:</p><ul><li>A comparison has an unsigned one-bit result, but signed Div/Rem/relational evaluation is determined from the two operand contexts. The official simulator correctly recomputes it from <code>lhs.expr_context.signed &amp;&amp; rhs.expr_context.signed</code>.</li><li>An ordinary packed bit/part select is unsigned. AIR retains the base variable and <code>VarSelect</code>; a consumer must not use the base declaration&#39;s signedness as the selected expression&#39;s signedness.</li><li>Unary <code>~</code> uses its operand evaluation context. Its result must not be inferred from unrelated parent/result metadata.</li></ul><p>Celox treating any one of those metadata fields as universal was a Celox AIR consumer bug. These cases must not be filed as analyzer bugs.</p><h2 id="numeric-width-cast-signedness-differs-from-emitted-systemverilog" tabindex="-1">Numeric width cast signedness differs from emitted SystemVerilog <a class="header-anchor" href="#numeric-width-cast-signedness-differs-from-emitted-systemverilog" aria-label="Permalink to &quot;Numeric width cast signedness differs from emitted SystemVerilog&quot;">​</a></h2><p>Minimal reproduction:</p><div class="language-veryl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">veryl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>module Top (</span></span>
<span class="line"><span>    a: input signed logic&lt;5&gt;,</span></span>
<span class="line"><span>    y: output logic&lt;16&gt;,</span></span>
<span class="line"><span>) {</span></span>
<span class="line"><span>    assign y = a as 8;</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>For <code>a = 5&#39;b11001</code> (<code>-7</code>), the emitter produces the SystemVerilog equivalent of <code>8&#39;(a)</code>. A SystemVerilog size cast preserves the self-determined expression&#39;s signedness, so that code produces <code>16&#39;hfff9</code>. The three existing paths disagree:</p><ul><li>the official simulator&#39;s runtime path treats the integer cast as transparent and produces <code>16&#39;h0019</code>, without first resizing five bits to eight;</li><li>analyzer constant evaluation resizes to <code>8&#39;hf9</code> but marks the cast result unsigned, producing <code>16&#39;h00f9</code> in the outer assignment;</li><li>emitted SystemVerilog produces <code>16&#39;hfff9</code>.</li></ul><p>Upstream&#39;s current regression explicitly expects unsigned behavior for an unsigned input, which cannot distinguish source-signedness preservation from always-unsigned behavior. This requires one shared rule across the analyzer, simulator, and emitter.</p><p>Cause:</p><ul><li><a href="https://github.com/veryl-lang/veryl/blob/0230fbe76b8b4fd67bc09b2aa0378a6e96e0683f/crates/analyzer/src/ir/expression.rs#L200-L207" target="_blank" rel="noreferrer"><code>Expression::gather_context</code> forces <code>ctx.signed = false</code> for every numeric <code>as</code> target</a>.</li><li>The simulator drops most integer cast nodes as transparent, so runtime and constant evaluation do not even agree on resizing.</li></ul><p>Upstream fix and regression:</p><ul><li>Implement the SystemVerilog size-cast rule used by the emitter: resize using the source expression&#39;s self-determined signedness and preserve that signedness on the result.</li><li>Test signed and unsigned runtime inputs and the equivalent constants, both when widening and when feeding <code>/</code>, <code>%</code>, comparison, and <code>&gt;&gt;&gt;</code>.</li></ul><h2 id="runtime-packed-select-keeps-the-base-signedness-in-downstream-operations" tabindex="-1">Runtime packed select keeps the base signedness in downstream operations <a class="header-anchor" href="#runtime-packed-select-keeps-the-base-signedness-in-downstream-operations" aria-label="Permalink to &quot;Runtime packed select keeps the base signedness in downstream operations&quot;">​</a></h2><p>Minimal reproduction:</p><div class="language-veryl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">veryl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>module Top (</span></span>
<span class="line"><span>    x: input signed logic&lt;8&gt;,</span></span>
<span class="line"><span>    y: output logic&lt;8&gt;,</span></span>
<span class="line"><span>) {</span></span>
<span class="line"><span>    assign y = x[7:0] &gt;&gt;&gt; 1;</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>For <code>x = 8&#39;hfe</code>, a packed part-select is unsigned even when it spans the whole vector. The emitted SystemVerilog therefore produces <code>8&#39;h7f</code>. All four official simulator backends in 0.20.2 instead produce <code>8&#39;hff</code>.</p><p>AIR correctly retains <code>VarSelect</code>, and evaluating the select as a <code>Value</code> clears its signed flag. The simulator&#39;s ProtoExpression conversion separately copies the base factor&#39;s signed expression context; the later arithmetic-shift selection reads that stale context and chooses a signed shift.</p><p>The fix must derive the post-select context from the selected expression, not blindly copy the base context. Regressions need bit selects, partial and full-width part-selects, dynamic selects, and the boundary where selecting one element of a packed array yields a named signed element type.</p><h2 id="boolean-conversion-loses-wide-and-four-state-values" tabindex="-1">Boolean conversion loses wide and four-state values <a class="header-anchor" href="#boolean-conversion-loses-wide-and-four-state-values" aria-label="Permalink to &quot;Boolean conversion loses wide and four-state values&quot;">​</a></h2><p>Minimal reproductions:</p><div class="language-veryl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">veryl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>module Top (</span></span>
<span class="line"><span>    wide_result: output logic,</span></span>
<span class="line"><span>    x_result: output logic,</span></span>
<span class="line"><span>) {</span></span>
<span class="line"><span>    const WIDE_ONE: logic&lt;65&gt; = 65&#39;d1;</span></span>
<span class="line"><span>    const ONE_X: logic&lt;2&gt; = 2&#39;b1x;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    always_comb {</span></span>
<span class="line"><span>        if WIDE_ONE { wide_result = 1&#39;b1; }</span></span>
<span class="line"><span>        else          { wide_result = 1&#39;b0; }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        if ONE_X { x_result = 1&#39;b1; }</span></span>
<span class="line"><span>        else       { x_result = 1&#39;b0; }</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Both conditions are true: one is a 65-bit value containing a known one, and the other contains a known one plus an unknown bit. The analyzer converts a condition through <code>Value::to_usize().unwrap_or(0)</code>. <code>Value::to_usize()</code> returns <code>None</code> for every <code>BigUint</code> value and for every value containing X/Z, so both conditions are folded as false. The same pattern affects procedural <code>if</code>, constant function execution, and generate-if selection.</p><p>A related constant ternary is also wrong:</p><div class="language-veryl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">veryl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>const C: logic = 1&#39;bx;</span></span>
<span class="line"><span>const Y: logic = if C ? 1&#39;b0 : 1&#39;b1;</span></span></code></pre></div><p>The emitted SystemVerilog yields X by merging the two arms. Analyzer constant evaluation selects the false arm because it uses the same lossy conversion.</p><p>Cause:</p><ul><li><a href="https://github.com/veryl-lang/veryl/blob/0230fbe76b8b4fd67bc09b2aa0378a6e96e0683f/crates/analyzer/src/conv/statement.rs#L417-L421" target="_blank" rel="noreferrer">procedural condition folding uses <code>to_usize().unwrap_or(0)</code></a></li><li><a href="https://github.com/veryl-lang/veryl/blob/0230fbe76b8b4fd67bc09b2aa0378a6e96e0683f/crates/analyzer/src/conv/declaration.rs#L207-L229" target="_blank" rel="noreferrer">generate-if conversion uses <code>to_usize().unwrap_or(0)</code></a></li><li><a href="https://github.com/veryl-lang/veryl/blob/0230fbe76b8b4fd67bc09b2aa0378a6e96e0683f/crates/analyzer/src/ir/expression.rs#L459-L473" target="_blank" rel="noreferrer">constant ternary evaluation uses <code>to_usize().unwrap_or(0)</code></a></li></ul><p>Upstream fix and regression:</p><ul><li>Add a value-level boolean conversion returning <code>False</code>, <code>True</code>, or <code>Unknown</code>, without converting the payload to a host integer. A known one makes the value true; no known one plus any X/Z makes it unknown; otherwise it is false.</li><li>Procedural and generate conditions take the true side only for <code>True</code>. Constant ternaries select an arm for <code>True</code>/<code>False</code> and merge arm bits for <code>Unknown</code>.</li><li>Cover U64 and BigUint storage, pure X/Z, known-one-plus-X/Z, and known bits above bit 64.</li></ul><h2 id="constant-folding-loses-operation-specific-type-information" tabindex="-1">Constant folding loses operation-specific type information <a class="header-anchor" href="#constant-folding-loses-operation-specific-type-information" aria-label="Permalink to &quot;Constant folding loses operation-specific type information&quot;">​</a></h2><p>Constant folding replaces an expression with <code>Expression::create_value</code>, then copies the old result type but not its expression context. Consumers can then see three contradictory facts: the folded <code>Value</code> signedness, the copied type signedness, and a default unsigned expression context. A folded ordinary packed select is one example; an integer type cast is another. No downstream consumer can recover the erased operator from those fields alone.</p><p>Packed enum selection also loses the selected value and width:</p><div class="language-veryl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">veryl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>module EnumSelect (</span></span>
<span class="line"><span>    y: output logic&lt;2&gt;,</span></span>
<span class="line"><span>) {</span></span>
<span class="line"><span>    enum Color: logic&lt;2&gt; {</span></span>
<span class="line"><span>        Red = 2&#39;d0,</span></span>
<span class="line"><span>        Blue = 2&#39;d2,</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    const COLORS: Color&lt;2&gt; = 4&#39;b1010;</span></span>
<span class="line"><span>    assign y = COLORS[0];</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Unmodified 0.20.2 analyzer IR lowers the final assignment to <code>1&#39;h0</code>; the selected enum element should retain its two-bit <code>Color</code> type and value <code>2&#39;h2</code>. This is an analyzer result, not a Celox source-rewrite artifact.</p><p>Constant selection must preserve both the selected element width and the selected named type. A packed array of a named signed element type is signed exactly when all dimensions outside that named type have been consumed. Selecting further inside that element, selecting only part of the outer aggregate, or taking a range is unsigned. Regressions therefore need enum elements, typedef aliases, nested named signed elements, ordinary bit/part selects, and constant/runtime forms. The ordinary unsigned-select rule is already discussed in <a href="https://github.com/veryl-lang/veryl/issues/94" target="_blank" rel="noreferrer">Veryl issue #94</a>.</p>`,42)])])}const g=s(o,[["render",i]]);export{h as __pageData,g as default};
